void ExpectAmflowPrefactorReferenceSpecContainsLockedEvidence(const std::string& yaml) {
  const std::vector<std::string> required_fragments = {
      kExpectedPrefactorReferenceVersion,
      kExpectedRetainedPhase0Key,
      kExpectedRetainedPhase0SourceReadme,
      kExpectedRetainedPhase0PrescriptionPolaritySource,
      kExpectedPlusI0LoopPrefactorLine,
      kExpectedCutPrefactorLine,
      kExpectedRepoSnapshotKey,
      kExpectedRepoSnapshotSourceReadme,
      kExpectedMinusI0LoopPrefactorLine,
      "notes:",
      kExpectedBatch58cAtomicityNote,
      kExpectedRetainedPhase0ProvenanceNote,
      kExpectedRepoSnapshotProvenanceNote,
      kExpectedPrescriptionOnlyNote,
      kExpectedMilestoneM3OpenNote,
      kExpectedMilestoneM4OpenNote,
  };

  for (const auto& fragment : required_fragments) {
    ExpectContains(yaml,
                   fragment,
                   "prefactor reference spec should contain locked fragment: " + fragment);
  }
}

struct AmflowPrefactorReferenceEvidence {
  std::string retained_phase0_source_readme;
  std::string retained_phase0_prescription_polarity_source;
  std::string plus_i0_loop_prefactor;
  std::string cut_prefactor;
  std::string repo_snapshot_source_readme;
  std::string minus_i0_loop_prefactor;
};

std::string ExtractQuotedYamlScalar(const std::string& yaml,
                                    const std::string& line_prefix,
                                    const std::string& message) {
  std::istringstream stream(yaml);
  for (std::string line; std::getline(stream, line);) {
    if (line.rfind(line_prefix, 0) != 0) {
      continue;
    }

    const std::string value = TrimAsciiWhitespace(line.substr(line_prefix.size()));
    Expect(value.size() >= 2 && value.front() == '"' && value.back() == '"',
           message + ": expected quoted scalar");
    return value.substr(1, value.size() - 2);
  }

  throw std::runtime_error(message + ": missing line with prefix " + line_prefix);
}

std::string ExtractQuotedYamlScalarAfterAnchor(const std::string& yaml,
                                               const std::string& anchor,
                                               const std::string& line_prefix,
                                               const std::string& message) {
  const std::size_t anchor_position = yaml.find(anchor);
  Expect(anchor_position != std::string::npos, message + ": missing anchor " + anchor);
  return ExtractQuotedYamlScalar(yaml.substr(anchor_position), line_prefix, message);
}

AmflowPrefactorReferenceEvidence ParseAmflowPrefactorReferenceEvidence(const std::string& yaml) {
  return {
      ExtractQuotedYamlScalarAfterAnchor(
          yaml,
          kExpectedRetainedPhase0Key,
          "  source_readme: ",
          "prefactor reference spec should declare retained phase-0 README provenance"),
      ExtractQuotedYamlScalarAfterAnchor(
          yaml,
          kExpectedRetainedPhase0Key,
          "  source_amflow_m_prescription_polarity: ",
          "prefactor reference spec should declare retained phase-0 AMFlow.m provenance"),
      ExtractQuotedYamlScalar(yaml,
                              "  plus_i0_loop_prefactor: ",
                              "prefactor reference spec should declare plus_i0_loop_prefactor"),
      ExtractQuotedYamlScalar(yaml,
                              "  cut_prefactor: ",
                              "prefactor reference spec should declare cut_prefactor"),
      ExtractQuotedYamlScalarAfterAnchor(
          yaml,
          kExpectedRepoSnapshotKey,
          "  source_readme: ",
          "prefactor reference spec should declare repo snapshot provenance"),
      ExtractQuotedYamlScalar(
          yaml,
          "  minus_i0_loop_prefactor: ",
          "prefactor reference spec should declare minus_i0_loop_prefactor"),
  };
}

std::string MarkdownBulletWithInlineCode(const std::string& value) {
  return "- `" + value + "`";
}

void ExpectAmflowPrefactorReferenceMirrorContainsLockedEvidence(
    const std::string& markdown,
    const AmflowPrefactorReferenceEvidence& evidence) {
  const std::vector<std::string> required_fragments = {
      kExpectedPrefactorMirrorHeading,
      kExpectedPrefactorMirrorStructuredArtifactPath,
      MarkdownBulletWithInlineCode(evidence.retained_phase0_source_readme),
      MarkdownBulletWithInlineCode(evidence.retained_phase0_prescription_polarity_source),
      MarkdownBulletWithInlineCode(evidence.repo_snapshot_source_readme),
      "- retained-root lock: `plus_i0_loop_prefactor = " + evidence.plus_i0_loop_prefactor + "`",
      "- retained-root lock: `cut_prefactor = " + evidence.cut_prefactor + "`",
      "- snapshot-backed only: `minus_i0_loop_prefactor = " + evidence.minus_i0_loop_prefactor +
          "`",
      kExpectedPrefactorMirrorPrescriptionVocabulary,
      kExpectedPrefactorMirrorMinusI0NonClaim,
      kExpectedPrefactorMirrorInsertPrefactorsNonClaim,
      kExpectedPrefactorMirrorReductionSpanNonClaim,
      kExpectedPrefactorMirrorMilestoneClosureNonClaim,
  };

  for (const auto& fragment : required_fragments) {
    ExpectContains(markdown,
                   fragment,
                   "prefactor reference mirror should contain locked fragment: " + fragment);
  }
}

std::size_t CountCutPropagators(const amflow::ProblemSpec& spec) {
  return static_cast<std::size_t>(
      std::count_if(spec.family.propagators.begin(),
                    spec.family.propagators.end(),
                    [](const amflow::Propagator& propagator) {
                      return propagator.kind == amflow::PropagatorKind::Cut;
                    }));
}

std::string BuildLockedOverallAmflowPrefactor(std::size_t loop_count,
                                              const std::string& loop_prefactor,
                                              std::size_t cut_count,
                                              const std::string& cut_prefactor) {
  std::vector<std::string> factors;
  factors.reserve(loop_count + cut_count);
  for (std::size_t index = 0; index < loop_count; ++index) {
    factors.push_back("(" + loop_prefactor + ")");
  }
  for (std::size_t index = 0; index < cut_count; ++index) {
    factors.push_back("(" + cut_prefactor + ")");
  }

  std::ostringstream stream;
  for (std::size_t index = 0; index < factors.size(); ++index) {
    if (index > 0) {
      stream << " * ";
    }
    stream << factors[index];
  }
  return stream.str();
}

amflow::ReductionOptions MakeKiraReductionOptions() {
  amflow::ReductionOptions options;
  options.ibp_reducer = "Kira";
  options.permutation_option = 1;
  return options;
}

std::size_t CountString(const std::vector<std::string>& values, const std::string& needle) {
  return static_cast<std::size_t>(std::count(values.begin(), values.end(), needle));
}

bool SameMasterIntegral(const amflow::MasterIntegral& lhs, const amflow::MasterIntegral& rhs) {
  return lhs.family == rhs.family && lhs.indices == rhs.indices && lhs.label == rhs.label;
}

bool SameDifferentiationVariable(const amflow::DifferentiationVariable& lhs,
                                 const amflow::DifferentiationVariable& rhs) {
  return lhs.name == rhs.name && lhs.kind == rhs.kind;
}

bool SameBoundaryCondition(const amflow::BoundaryCondition& lhs,
                           const amflow::BoundaryCondition& rhs) {
  return lhs.variable == rhs.variable && lhs.location == rhs.location &&
         lhs.values == rhs.values && lhs.strategy == rhs.strategy;
}

bool SameBoundaryRequest(const amflow::BoundaryRequest& lhs,
                         const amflow::BoundaryRequest& rhs) {
  return lhs.variable == rhs.variable && lhs.location == rhs.location &&
         lhs.strategy == rhs.strategy;
}

bool SameDESystem(const amflow::DESystem& lhs, const amflow::DESystem& rhs) {
  if (lhs.masters.size() != rhs.masters.size() || lhs.variables.size() != rhs.variables.size() ||
      lhs.coefficient_matrices != rhs.coefficient_matrices ||
      lhs.singular_points != rhs.singular_points) {
    return false;
  }
  for (std::size_t index = 0; index < lhs.masters.size(); ++index) {
    if (!SameMasterIntegral(lhs.masters[index], rhs.masters[index])) {
      return false;
    }
  }
  for (std::size_t index = 0; index < lhs.variables.size(); ++index) {
    if (!SameDifferentiationVariable(lhs.variables[index], rhs.variables[index])) {
      return false;
    }
  }
  return true;
}

bool DESystemContainsStandaloneIdentifier(const amflow::DESystem& system,
                                          const std::string& identifier) {
  for (const auto& [variable_name, matrix] : system.coefficient_matrices) {
    static_cast<void>(variable_name);
    for (const auto& row : matrix) {
      for (const auto& cell : row) {
        if (ContainsStandaloneIdentifier(cell, identifier)) {
          return true;
        }
      }
    }
  }
  for (const auto& singular_point : system.singular_points) {
    if (ContainsStandaloneIdentifier(singular_point, identifier)) {
      return true;
    }
  }
  return false;
}

void ExpectSymbolicDimensionExpressionRewrittenEtaDESystem(
    const amflow::DESystem& system,
    const amflow::DESystem& baseline_system,
    const std::string& context) {
  Expect(amflow::ValidateDESystem(system).empty(), context + " should return a valid DESystem");
  Expect(system.masters.size() == baseline_system.masters.size() &&
             system.variables.size() == baseline_system.variables.size() &&
             system.coefficient_matrices.size() == baseline_system.coefficient_matrices.size(),
         context + " should preserve the assembled DESystem shape");
  Expect(!SameDESystem(system, baseline_system),
         context + " should rewrite the dimension-dependent DESystem when the explicit dimension "
                   "expression is symbolic");
  Expect(!DESystemContainsStandaloneIdentifier(system, "dimension"),
         context + " should not preserve the canonical dimension identifier after rewriting the "
                   "explicit symbolic dimension expression");
  Expect(DESystemContainsStandaloneIdentifier(system, "D0"),
         context + " should substitute the caller-supplied symbolic dimension expression into "
                   "the assembled DESystem");
  Expect(DESystemContainsStandaloneIdentifier(system, "eps"),
         context + " should preserve the caller-supplied symbolic eps dependence in the "
                   "assembled DESystem");
}

bool SamePrecisionPolicy(const amflow::PrecisionPolicy& lhs, const amflow::PrecisionPolicy& rhs) {
  return lhs.working_precision == rhs.working_precision &&
         lhs.chop_precision == rhs.chop_precision &&
         lhs.rationalize_precision == rhs.rationalize_precision &&
         lhs.escalation_step == rhs.escalation_step &&
         lhs.max_working_precision == rhs.max_working_precision &&
         lhs.x_order == rhs.x_order && lhs.x_order_step == rhs.x_order_step;
}

bool SameAmfSolveRuntimePolicy(const amflow::AmfSolveRuntimePolicy& lhs,
                               const amflow::AmfSolveRuntimePolicy& rhs) {
  return lhs.extra_x_order == rhs.extra_x_order &&
         lhs.learn_x_order == rhs.learn_x_order &&
         lhs.test_x_order == rhs.test_x_order && lhs.run_length == rhs.run_length;
}

bool SameEtaContourSingularPoint(const amflow::EtaContourSingularPoint& lhs,
                                 const amflow::EtaContourSingularPoint& rhs) {
  return lhs.expression == rhs.expression && lhs.value == rhs.value &&
         lhs.branch_winding == rhs.branch_winding;
}

bool SameEtaContinuationPlan(const amflow::EtaContinuationPlan& lhs,
                             const amflow::EtaContinuationPlan& rhs) {
  if (lhs.eta_symbol != rhs.eta_symbol || lhs.start_location != rhs.start_location ||
      lhs.target_location != rhs.target_location || lhs.half_plane != rhs.half_plane ||
      lhs.contour_points != rhs.contour_points || lhs.contour_fingerprint != rhs.contour_fingerprint ||
      lhs.singular_points.size() != rhs.singular_points.size()) {
    return false;
  }
  for (std::size_t index = 0; index < lhs.singular_points.size(); ++index) {
    if (!SameEtaContourSingularPoint(lhs.singular_points[index], rhs.singular_points[index])) {
      return false;
    }
  }
  return true;
}

bool SameSolveRequest(const amflow::SolveRequest& lhs, const amflow::SolveRequest& rhs) {
  if (!SameDESystem(lhs.system, rhs.system) ||
      lhs.boundary_requests.size() != rhs.boundary_requests.size() ||
      lhs.boundary_conditions.size() != rhs.boundary_conditions.size() ||
      lhs.start_location != rhs.start_location ||
      lhs.target_location != rhs.target_location ||
      !SamePrecisionPolicy(lhs.precision_policy, rhs.precision_policy) ||
      lhs.amf_runtime_policy.has_value() != rhs.amf_runtime_policy.has_value() ||
      (lhs.amf_runtime_policy.has_value() &&
       !SameAmfSolveRuntimePolicy(*lhs.amf_runtime_policy, *rhs.amf_runtime_policy)) ||
      lhs.eta_continuation_plan.has_value() != rhs.eta_continuation_plan.has_value() ||
      (lhs.eta_continuation_plan.has_value() &&
       !SameEtaContinuationPlan(*lhs.eta_continuation_plan,
                                *rhs.eta_continuation_plan)) ||
      lhs.requested_digits != rhs.requested_digits) {
    return false;
  }
  for (std::size_t index = 0; index < lhs.boundary_requests.size(); ++index) {
    if (!SameBoundaryRequest(lhs.boundary_requests[index], rhs.boundary_requests[index])) {
      return false;
    }
  }
  for (std::size_t index = 0; index < lhs.boundary_conditions.size(); ++index) {
    if (!SameBoundaryCondition(lhs.boundary_conditions[index], rhs.boundary_conditions[index])) {
      return false;
    }
  }
  return true;
}

bool SameSolverDiagnostics(const amflow::SolverDiagnostics& lhs,
                           const amflow::SolverDiagnostics& rhs) {
  return lhs.success == rhs.success && lhs.residual_norm == rhs.residual_norm &&
         lhs.overlap_mismatch == rhs.overlap_mismatch &&
         lhs.failure_code == rhs.failure_code && lhs.summary == rhs.summary;
}

