amflow::ProblemSpec MakeLoopPrescriptionAwareCutkoskyPhaseSpaceSpec(
    const amflow::FeynmanPrescription cut_prescription) {
  amflow::ProblemSpec spec = amflow::MakeSampleProblemSpec();
  spec.family.loop_prescriptions = {cut_prescription, amflow::FeynmanPrescription::None};
  spec.family.propagators[0].kind = amflow::PropagatorKind::Cut;
  spec.family.propagators[0].prescription = static_cast<int>(cut_prescription);
  spec.family.propagators[1].kind = amflow::PropagatorKind::Cut;
  spec.family.propagators[1].prescription = static_cast<int>(cut_prescription);
  return spec;
}

amflow::ProblemSpec MakeMixedLoopPrescriptionAwareCutkoskyPhaseSpaceSpec() {
  amflow::ProblemSpec spec = amflow::MakeSampleProblemSpec();
  spec.family.loop_prescriptions = {amflow::FeynmanPrescription::PlusI0,
                                    amflow::FeynmanPrescription::None};
  spec.family.propagators[0].kind = amflow::PropagatorKind::Cut;
  spec.family.propagators[0].prescription = 1;
  spec.family.propagators[3].kind = amflow::PropagatorKind::Cut;
  spec.family.propagators[3].prescription = 0;
  return spec;
}

amflow::ProblemSpec MakeLoopPrescriptionMismatchCutkoskyPhaseSpaceSpec() {
  amflow::ProblemSpec spec = MakeLoopPrescriptionAwareCutkoskyPhaseSpaceSpec(
      amflow::FeynmanPrescription::PlusI0);
  spec.family.propagators[1].prescription = -1;
  return spec;
}

amflow::ProblemSpec MakeRawPrescriptionCutkoskyPhaseSpaceSpec(
    const amflow::FeynmanPrescription cut_prescription) {
  amflow::ProblemSpec spec = MakeReviewedCutkoskyPhaseSpaceSpec();
  spec.family.propagators[0].prescription = static_cast<int>(cut_prescription);
  spec.family.propagators[5].prescription = static_cast<int>(cut_prescription);
  return spec;
}

amflow::ProblemSpec MakeMixedRawPrescriptionCutkoskyPhaseSpaceSpec() {
  amflow::ProblemSpec spec =
      MakeRawPrescriptionCutkoskyPhaseSpaceSpec(amflow::FeynmanPrescription::PlusI0);
  spec.family.propagators[5].prescription =
      static_cast<int>(amflow::FeynmanPrescription::None);
  return spec;
}

amflow::FamilyDefinition MakeAutomaticPhaseSpaceLoopPrescriptionFamily() {
  amflow::FamilyDefinition family;
  family.name = "phase";
  family.loop_momenta = {"l1", "l2"};
  family.loop_prescriptions = {amflow::FeynmanPrescription::None,
                               amflow::FeynmanPrescription::None};
  family.propagators = {
      amflow::Propagator("l1^2-msq"),
      amflow::Propagator("(l1+p1)^2"),
      amflow::Propagator("l2^2"),
      amflow::Propagator("(l1+l2+p1)^2"),
      amflow::Propagator("(l1+l2+p1+p2)^2"),
      amflow::Propagator("(l1+l2+p2)^2"),
      amflow::Propagator("(l1+p2)^2"),
  };
  return family;
}

amflow::FamilyDefinition MakeFeynmanPrescriptionLoopPrescriptionFamily() {
  amflow::FamilyDefinition family;
  family.name = "loopxloop";
  family.loop_momenta = {"l1", "l2", "q"};
  family.loop_prescriptions = {amflow::FeynmanPrescription::PlusI0,
                               amflow::FeynmanPrescription::MinusI0,
                               amflow::FeynmanPrescription::None};
  family.propagators = {
      amflow::Propagator("l1^2"),
      amflow::Propagator("(l1+p1)^2"),
      amflow::Propagator("(l1+p1+p2)^2"),
      amflow::Propagator("(l1+q)^2"),
      amflow::Propagator("l2^2"),
      amflow::Propagator("(l2-p2)^2"),
      amflow::Propagator("(l2-p2-p1)^2"),
      amflow::Propagator("(l2-q)^2"),
      amflow::Propagator("q^2-msq"),
      amflow::Propagator("(p1+p2-q)^2-m2sq"),
      amflow::Propagator("(l1-l2)^2"),
      amflow::Propagator("(p1-q)^2"),
  };
  return family;
}

