amflow::SolveRequest MakeCutkoskyPhaseSpaceSolveTemplateRequestWithEtaSymbol(
    const std::string& eta_symbol) {
  amflow::SolveRequest solve_request = MakeCutkoskyPhaseSpaceSolveTemplateRequest();
  if (eta_symbol == "eta") {
    return solve_request;
  }

  const auto matrix = solve_request.system.coefficient_matrices.at("eta");
  const amflow::DifferentiationVariableKind variable_kind =
      solve_request.system.variables.front().kind;
  solve_request.system.variables = {{eta_symbol, variable_kind}};
  solve_request.system.coefficient_matrices.clear();
  solve_request.system.coefficient_matrices[eta_symbol] = matrix;
  solve_request.system.singular_points = {eta_symbol + "=0"};
  solve_request.target_location = eta_symbol + "=0";
  return solve_request;
}

amflow::BoundaryRequest GeneratePlannedEtaInfinityBoundaryRequestFromAmfOptionsBaseline(
    const amflow::ProblemSpec& spec,
    const amflow::AmfOptions& amf_options,
    const std::vector<std::shared_ptr<amflow::EndingScheme>>& user_defined_schemes,
    const std::string& eta_symbol = "eta") {
  if (amf_options.ending_schemes.empty()) {
    throw std::invalid_argument("ending-scheme list must not be empty");
  }

  std::exception_ptr last_failure;
  for (const std::string& ending_scheme_name : amf_options.ending_schemes) {
    const std::shared_ptr<amflow::EndingScheme> ending_scheme =
        amflow::ResolveEndingScheme(ending_scheme_name, user_defined_schemes);

    amflow::EndingDecision decision;
    try {
      decision = ending_scheme->Plan(spec);
    } catch (const std::exception&) {
      last_failure = std::current_exception();
      continue;
    }

    try {
      const std::string supported_terminal_node = spec.family.name + "::eta->infinity";
      const std::size_t supported_count =
          static_cast<std::size_t>(std::count(decision.terminal_nodes.begin(),
                                              decision.terminal_nodes.end(),
                                              supported_terminal_node));
      if (supported_count > 1) {
        throw amflow::BoundaryUnsolvedError(
            "planned eta->infinity boundary request requires exactly one supported terminal "
            "node " +
            supported_terminal_node + "; duplicate supported terminal node");
      }

      for (const std::string& terminal_node : decision.terminal_nodes) {
        if (terminal_node != supported_terminal_node) {
          throw amflow::BoundaryUnsolvedError(
              "planned eta->infinity boundary request requires exactly one supported terminal "
              "node " +
              supported_terminal_node + "; unsupported extra terminal node " + terminal_node);
        }
      }

      if (supported_count == 0) {
        throw amflow::BoundaryUnsolvedError(
            "planned eta->infinity boundary request requires exactly one supported terminal "
            "node " +
            supported_terminal_node + "; missing supported terminal node");
      }

      return amflow::GenerateBuiltinEtaInfinityBoundaryRequest(spec, eta_symbol);
    } catch (const amflow::BoundaryUnsolvedError&) {
      last_failure = std::current_exception();
    } catch (const std::runtime_error&) {
      last_failure = std::current_exception();
    } catch (const std::invalid_argument&) {
      throw;
    }
  }

  if (!last_failure) {
    throw std::runtime_error(
        "Batch 65a ending-scheme baseline exhausted without recording a terminal failure");
  }
  std::rethrow_exception(last_failure);
}

amflow::SolverDiagnostics SolveAmfOptionsEndingSchemeEtaInfinitySeriesManualBaseline(
    const amflow::ProblemSpec& spec,
    const amflow::AmfOptions& amf_options,
    const std::vector<std::shared_ptr<amflow::EndingScheme>>& user_defined_schemes,
    const amflow::SolveRequest& request_template,
    const amflow::BoundaryProvider& provider,
    const amflow::SeriesSolver& solver,
    const std::string& eta_symbol = "eta") {
  const amflow::BoundaryRequest request =
      GeneratePlannedEtaInfinityBoundaryRequestFromAmfOptionsBaseline(spec,
                                                                      amf_options,
                                                                      user_defined_schemes,
                                                                      eta_symbol);

  amflow::SolveRequest solve_request = request_template;
  solve_request.boundary_requests = {request};

  const amflow::SolveRequest attached =
      amflow::AttachBoundaryConditionsFromProvider(solve_request, provider);
  return solver.Solve(attached);
}

amflow::SolverDiagnostics SolveAmfOptionsEndingSchemeCutkoskyPhaseSpaceSeriesManualBaseline(
    const amflow::ProblemSpec& spec,
    const amflow::AmfOptions& amf_options,
    const std::vector<std::shared_ptr<amflow::EndingScheme>>& user_defined_schemes,
    const amflow::SolveRequest& request_template,
    const amflow::BoundaryProvider& provider,
    const amflow::SeriesSolver& solver,
    const std::string& eta_symbol = "eta") {
  const amflow::BoundaryRequest request =
      amflow::GenerateAmfOptionsEndingSchemeCutkoskyPhaseSpaceBoundaryRequest(spec,
                                                                              amf_options,
                                                                              user_defined_schemes,
                                                                              eta_symbol);

  amflow::SolveRequest solve_request = request_template;
  solve_request.boundary_requests = {request};

  const amflow::SolveRequest attached =
      amflow::AttachBoundaryConditionsFromProvider(solve_request, provider);
  return solver.Solve(attached);
}

amflow::SolverDiagnostics MakeRequestDrivenEquivalenceHarnessDiagnostics(
    const amflow::SolveRequest& request) {
  amflow::SolverDiagnostics diagnostics;
  diagnostics.success = true;
  const std::size_t boundary_value_count =
      request.boundary_conditions.empty() ? 0 : request.boundary_conditions.front().values.size();
  const std::size_t summary_size = request.start_location.size() + request.target_location.size() +
                                   request.boundary_conditions.size() + boundary_value_count;
  diagnostics.residual_norm = static_cast<double>(
                                  request.system.masters.size() * 16 +
                                  request.boundary_requests.size() * 8 +
                                  request.boundary_conditions.size() * 4 +
                                  request.system.variables.size() * 2 +
                                  (request.requested_digits % 16)) /
                              1024.0;
  diagnostics.overlap_mismatch =
      static_cast<double>(summary_size + request.precision_policy.x_order_step) / 512.0;
  diagnostics.failure_code.clear();
  diagnostics.summary = "recorded deterministic eta-infinity boundary solve from " +
                        request.start_location + " to " + request.target_location + " with " +
                        std::to_string(request.boundary_conditions.size()) +
                        " attached conditions";
  return diagnostics;
}

amflow::SolveRequest MakeManualStartBoundarySolveRequest(
    const amflow::DESystem& system,
    const std::string& variable_name,
    const std::string& start_location,
    const std::string& target_location,
    const std::vector<std::string>& boundary_values) {
  amflow::SolveRequest request;
  request.system = system;
  request.boundary_requests = {{variable_name, start_location, "manual"}};
  request.boundary_conditions = {{variable_name, start_location, boundary_values, "manual"}};
  request.start_location = start_location;
  request.target_location = target_location;
  request.precision_policy = MakeDistinctPrecisionPolicy();
  request.requested_digits = 73;
  return request;
}

class RecordingStaticBoundaryProvider final : public amflow::BoundaryProvider {
 public:
  RecordingStaticBoundaryProvider(
      const std::string& strategy,
      const std::vector<amflow::BoundaryCondition>& provided_conditions)
      : strategy_(strategy), provided_conditions_(provided_conditions) {}

  std::string Strategy() const override {
    ++strategy_call_count_;
    return strategy_;
  }

  amflow::BoundaryCondition Provide(const amflow::DESystem&,
                                    const amflow::BoundaryRequest& request) const override {
    ++provide_call_count_;
    seen_requests_.push_back(request);
    if (next_condition_index_ >= provided_conditions_.size()) {
      throw std::runtime_error("unexpected boundary-provider call");
    }
    return provided_conditions_[next_condition_index_++];
  }

  int strategy_call_count() const {
    return strategy_call_count_;
  }

  int provide_call_count() const {
    return provide_call_count_;
  }

  const std::vector<amflow::BoundaryRequest>& seen_requests() const {
    return seen_requests_;
  }

 private:
  std::string strategy_;
  std::vector<amflow::BoundaryCondition> provided_conditions_;
  mutable int strategy_call_count_ = 0;
  mutable int provide_call_count_ = 0;
  mutable std::size_t next_condition_index_ = 0;
  mutable std::vector<amflow::BoundaryRequest> seen_requests_;
};

class ThrowingBoundaryProvider final : public amflow::BoundaryProvider {
 public:
  ThrowingBoundaryProvider(const std::string& strategy, const std::string& message)
      : strategy_(strategy), message_(message) {}

  std::string Strategy() const override {
    ++strategy_call_count_;
    return strategy_;
  }

  amflow::BoundaryCondition Provide(const amflow::DESystem&,
                                    const amflow::BoundaryRequest&) const override {
    ++provide_call_count_;
    throw amflow::BoundaryUnsolvedError(message_);
  }

  int strategy_call_count() const {
    return strategy_call_count_;
  }

  int provide_call_count() const {
    return provide_call_count_;
  }

 private:
  std::string strategy_;
  std::string message_;
  mutable int strategy_call_count_ = 0;
  mutable int provide_call_count_ = 0;
};

