const amflow::ParsedReductionRule& FindRuleByTarget(
    const std::vector<amflow::ParsedReductionRule>& rules,
    const std::string& target_label) {
  for (const auto& rule : rules) {
    if (rule.target.Label() == target_label) {
      return rule;
    }
  }
  throw std::runtime_error("failed to find parsed reduction rule for target: " + target_label);
}

const amflow::ParsedReductionTerm& FindTermByMaster(const amflow::ParsedReductionRule& rule,
                                                    const std::string& master_label) {
  for (const auto& term : rule.terms) {
    if (term.master.Label() == master_label) {
      return term;
    }
  }
  throw std::runtime_error("failed to find parsed reduction term for master: " + master_label);
}

void WriteExecutableScript(const std::filesystem::path& path, const std::string& body) {
  {
    std::ofstream stream(path);
    stream << body;
  }
  std::filesystem::permissions(
      path,
      std::filesystem::perms::owner_read | std::filesystem::perms::owner_write |
          std::filesystem::perms::owner_exec | std::filesystem::perms::group_read |
          std::filesystem::perms::group_exec | std::filesystem::perms::others_read |
          std::filesystem::perms::others_exec,
      std::filesystem::perm_options::replace);
}

std::filesystem::path SolvedPathCacheDir(const amflow::ArtifactLayout& layout) {
  return layout.root / "cache" / "solved-paths";
}

std::size_t CountRegularFilesInDirectory(const std::filesystem::path& directory) {
  std::size_t count = 0;
  if (std::filesystem::exists(directory)) {
    for (const auto& entry : std::filesystem::directory_iterator(directory)) {
      if (entry.is_regular_file()) {
        ++count;
      }
    }
  }
  return count;
}

std::filesystem::path RequireOnlySolvedPathCacheManifestPath(
    const amflow::ArtifactLayout& layout,
    const std::string& message) {
  const std::filesystem::path cache_dir = SolvedPathCacheDir(layout);
  std::vector<std::filesystem::path> manifests;
  if (std::filesystem::exists(cache_dir)) {
    for (const auto& entry : std::filesystem::directory_iterator(cache_dir)) {
      if (entry.is_regular_file()) {
        manifests.push_back(entry.path());
      }
    }
  }

  Expect(manifests.size() == 1,
         message + "; expected exactly one solved-path cache manifest but found " +
             std::to_string(manifests.size()));
  return manifests.front();
}

std::filesystem::path RequireOnlyContinuationPlanManifestPath(
    const amflow::ArtifactLayout& layout,
    const std::string& message) {
  std::vector<std::filesystem::path> manifests;
  if (std::filesystem::exists(layout.manifests_dir)) {
    for (const auto& entry : std::filesystem::directory_iterator(layout.manifests_dir)) {
      if (entry.is_regular_file()) {
        manifests.push_back(entry.path());
      }
    }
  }

  Expect(manifests.size() == 1,
         message + "; expected exactly one continuation-plan manifest but found " +
             std::to_string(manifests.size()));
  return manifests.front();
}

std::filesystem::path ExpectedComplexEtaContinuationManifestPathForTests(
    const amflow::ArtifactLayout& layout,
    const amflow::EtaContinuationPlan& plan) {
  constexpr std::size_t kFingerprintPrefixLength = 12;
  std::string run_id = "eta-generated-complex-continuation";
  if (!plan.contour_fingerprint.empty()) {
    run_id += "-" + plan.contour_fingerprint.substr(
                           0, std::min(kFingerprintPrefixLength, plan.contour_fingerprint.size()));
  }
  return layout.manifests_dir / (run_id + ".yaml");
}

std::string ExtractYamlScalarValue(const std::string& yaml, const std::string& key) {
  const std::string prefix = key + ": ";
  std::istringstream input(yaml);
  std::string line;
  while (std::getline(input, line)) {
    if (line.rfind(prefix, 0) == 0) {
      return line.substr(prefix.size());
    }
  }
  throw std::runtime_error("failed to find YAML scalar key: " + key);
}

void ExpectSolvedPathCacheManifestMatchesBaseline(const std::string& actual_yaml,
                                                  const std::string& baseline_yaml,
                                                  const std::string& expected_solve_kind,
                                                  const std::string& context) {
  Expect(actual_yaml.find("manifest_kind: \"solved-path-cache\"\n") != std::string::npos,
         context + " should write the solved-path cache manifest kind");
  Expect(actual_yaml.find("solve_kind: \"" + expected_solve_kind + "\"\n") != std::string::npos,
         context + " should preserve the expected solved-path solve_kind identity");
  Expect(ExtractYamlScalarValue(actual_yaml, "solve_kind") ==
             ExtractYamlScalarValue(baseline_yaml, "solve_kind"),
         context + " should preserve solved-path solve_kind relative to the wrapper baseline");
  Expect(ExtractYamlScalarValue(actual_yaml, "slot_name") ==
             ExtractYamlScalarValue(baseline_yaml, "slot_name"),
         context + " should preserve the solved-path slot name relative to the wrapper baseline");
  Expect(ExtractYamlScalarValue(actual_yaml, "input_fingerprint") ==
             ExtractYamlScalarValue(baseline_yaml, "input_fingerprint"),
         context + " should preserve the solved-path input fingerprint relative to the wrapper "
                   "baseline");
  Expect(ExtractYamlScalarValue(actual_yaml, "request_fingerprint") ==
             ExtractYamlScalarValue(baseline_yaml, "request_fingerprint"),
         context + " should preserve the solved-path request fingerprint relative to the wrapper "
                   "baseline");
  Expect(ExtractYamlScalarValue(actual_yaml, "request_summary") ==
             ExtractYamlScalarValue(baseline_yaml, "request_summary"),
         context + " should preserve the solved-path request summary relative to the wrapper "
                   "baseline");
  Expect(ExtractYamlScalarValue(actual_yaml, "summary") ==
             ExtractYamlScalarValue(baseline_yaml, "summary"),
         context + " should preserve the cached diagnostics summary relative to the wrapper "
                   "baseline");
}

std::string MakeReducerFailureScript(const std::string& stderr_marker,
                                     const int exit_code = 9) {
  std::ostringstream script;
  script << "#!/bin/sh\n";
  script << "echo " << ShellSingleQuote(stderr_marker) << " 1>&2\n";
  script << "exit " << exit_code << "\n";
  return script.str();
}

std::string MakeSemanticDriftedReductionRules(std::string contents) {
  if (contents.find("2*planar_double_box[1,0,1,0,0,0,1]") != std::string::npos) {
    ReplaceFirst(contents,
                 "2*planar_double_box[1,0,1,0,0,0,1]",
                 "17*planar_double_box[1,0,1,0,0,0,1]");
    return contents;
  }

  if (contents.find("2*planar_double_box[1,1,1,1,1,1,1]") != std::string::npos) {
    ReplaceFirst(contents,
                 "2*planar_double_box[1,1,1,1,1,1,1]",
                 "17*planar_double_box[1,1,1,1,1,1,1]");
    return contents;
  }

  throw std::runtime_error("failed to recognize reduction rules for semantic drift mutation");
}

std::filesystem::path RequirePreparedKiraFilePath(const amflow::ArtifactLayout& layout,
                                                  const std::filesystem::path& relative_path,
                                                  const std::string& message) {
  const std::filesystem::path path = layout.generated_config_dir / relative_path;
  Expect(std::filesystem::exists(path),
         message + "; missing prepared Kira file: " + path.string());
  return path;
}

void OverwriteTextFile(const std::filesystem::path& path, const std::string& contents) {
  std::ofstream stream(path, std::ios::out | std::ios::trunc);
  if (!stream) {
    throw std::runtime_error("failed to open file for overwrite: " + path.string());
  }
  stream << contents;
  if (!stream) {
    throw std::runtime_error("failed to overwrite file: " + path.string());
  }
}

void MutateReductionRuleFilesForSemanticDrift(const amflow::ArtifactLayout& layout,
                                              const std::string& message) {
  std::vector<std::filesystem::path> paths;
  for (const std::filesystem::path& root :
       {layout.generated_config_dir / "results", layout.results_dir}) {
    if (!std::filesystem::exists(root)) {
      continue;
    }

    for (const auto& entry : std::filesystem::recursive_directory_iterator(root)) {
      if (entry.is_regular_file() && entry.path().filename() == "kira_target.m") {
        paths.push_back(entry.path());
      }
    }
  }

  Expect(!paths.empty(), message + "; failed to find any eta-generated kira_target.m files");
  for (const auto& path : paths) {
    OverwriteTextFile(path, MakeSemanticDriftedReductionRules(ReadFile(path)));
  }
}

