void LoadedSpecValidationRejectsMalformedTargetsTest() {
  const amflow::ProblemSpec sample = amflow::MakeSampleProblemSpec();
  const std::string canonical_yaml = amflow::SerializeProblemSpecYaml(sample);

  std::string missing_indices_yaml = canonical_yaml;
  ReplaceFirst(missing_indices_yaml, "    indices: [1, 1, 1, 1, 1, 1, 1]\n", "    indices: []\n");
  const auto missing_indices_messages =
      amflow::ValidateLoadedProblemSpec(amflow::ParseProblemSpecYaml(missing_indices_yaml));
  Expect(ContainsSubstring(missing_indices_messages, "targets[0].indices must not be empty"),
         "loaded-spec validation should reject empty target indices");

  std::string short_indices_yaml = canonical_yaml;
  ReplaceFirst(short_indices_yaml, "    indices: [1, 1, 1, 1, 1, 1, 1]\n", "    indices: [1, 1]\n");
  const auto short_indices_messages =
      amflow::ValidateLoadedProblemSpec(amflow::ParseProblemSpecYaml(short_indices_yaml));
  Expect(
      ContainsSubstring(short_indices_messages,
                        "targets[0].indices size must match family.propagators size"),
      "loaded-spec validation should reject target arity mismatches");
}

void UnknownFieldsAreIgnoredTest() {
  const amflow::ProblemSpec sample = amflow::MakeSampleProblemSpec();
  const std::string canonical_yaml = amflow::SerializeProblemSpecYaml(sample);
  std::string extended_yaml = canonical_yaml;

  InsertBefore(extended_yaml, "  propagators:\n",
               "  future_family:\n"
               "    tag: \"ignored\"\n");
  InsertBefore(extended_yaml, "  outgoing_momenta:",
               "  future_kinematics:\n"
               "    owner: \"ignored\"\n");
  InsertBefore(extended_yaml, "    indices: [",
               "    future_target_field:\n"
               "      note: \"ignored\"\n");
  InsertBefore(extended_yaml, "dimension:",
               "future_top_level:\n"
               "  enabled: true\n");

  const amflow::ProblemSpec loaded = amflow::ParseProblemSpecYaml(extended_yaml);
  const auto messages = amflow::ValidateLoadedProblemSpec(loaded);
  Expect(messages.empty(), "unknown additive fields should be ignored by the bootstrap loader");
  Expect(amflow::SerializeProblemSpecYaml(loaded) == canonical_yaml,
         "ignored additive fields should not change the canonicalized spec");
}

void DuplicateKeysAreRejectedTest() {
  const std::string canonical_yaml =
      amflow::SerializeProblemSpecYaml(amflow::MakeSampleProblemSpec());

  std::string duplicate_family_yaml = canonical_yaml;
  InsertBefore(duplicate_family_yaml, "  loop_momenta: [", "  name: \"shadowed\"\n");
  ExpectParseFailure(duplicate_family_yaml, "duplicate family field: name",
                     "duplicate family keys should be rejected");

  std::string duplicate_map_yaml = canonical_yaml;
  InsertBefore(duplicate_map_yaml, "    t: \"-10/3\"\n", "    s: \"31\"\n");
  ExpectParseFailure(duplicate_map_yaml, "duplicate mapping entry: s",
                     "duplicate numeric_substitutions entries should be rejected");

  std::string complex_yaml = canonical_yaml;
  ReplaceFirst(complex_yaml,
               "targets:\n",
               "  complex_numeric_substitutions:\n"
               "    s: \"30 + I/7\"\n"
               "    s: \"31 + I/9\"\n"
               "targets:\n");
  ExpectParseFailure(complex_yaml, "duplicate mapping entry: s",
                     "duplicate complex_numeric_substitutions entries should be rejected");
}

void ValidateProblemSpecRejectsComplexNumericSubstitutionsWithoutComplexModeTest() {
  amflow::ProblemSpec spec = amflow::MakeSampleProblemSpec();
  spec.kinematics.numeric_substitutions.erase("s");
  spec.kinematics.complex_numeric_substitutions = {
      {"s", "30 + I/7"},
  };

  const auto messages = amflow::ValidateProblemSpec(spec);
  Expect(ContainsSubstring(messages,
                           "kinematics.complex_numeric_substitutions require complex_mode: true"),
         "complex numeric substitutions should require complex_mode to be enabled");
}

void ValidateProblemSpecRejectsOverlappingExactAndComplexNumericSubstitutionsTest() {
  amflow::ProblemSpec spec = amflow::MakeSampleProblemSpec();
  spec.complex_mode = true;
  spec.kinematics.complex_numeric_substitutions = {
      {"s", "30 + I/7"},
  };

  const auto messages = amflow::ValidateProblemSpec(spec);
  Expect(ContainsSubstring(messages,
                           "kinematics.complex_numeric_substitutions entry for \"s\" must not "
                           "also appear in kinematics.numeric_substitutions"),
         "the same invariant should not be accepted in both exact and complex substitution maps");
}

void PropagatorVariantVocabularyAndLegacyFallbackTest() {
  Expect(amflow::ParsePropagatorVariantKeyword("quadratic") ==
             amflow::PropagatorVariant::Quadratic,
         "quadratic should map to the frozen quadratic propagator variant");
  Expect(amflow::ParsePropagatorVariantKeyword("linear") == amflow::PropagatorVariant::Linear,
         "linear should map to the frozen linear propagator variant");
  Expect(!amflow::ParsePropagatorVariantKeyword("cubic").has_value(),
         "out-of-vocabulary propagator variants should be rejected");

  amflow::Propagator standard;
  Expect(amflow::EffectivePropagatorVariant(standard) == amflow::PropagatorVariant::Quadratic,
         "legacy Standard propagators should keep the quadratic fallback variant");

  amflow::Propagator legacy_linear;
  legacy_linear.kind = amflow::PropagatorKind::Linear;
  Expect(amflow::EffectivePropagatorVariant(legacy_linear) == amflow::PropagatorVariant::Linear,
         "legacy Linear propagator kinds should still resolve to the linear variant");
}

void ValidateProblemSpecRejectsMismatchedExplicitPropagatorVariantTest() {
  amflow::ProblemSpec spec = amflow::MakeSampleProblemSpec();
  spec.family.propagators[0].variant = amflow::PropagatorVariant::Linear;

  const auto messages = amflow::ValidateProblemSpec(spec);
  Expect(ContainsSubstring(messages,
                           "family.propagators[0].variant must be \"quadratic\" when kind is "
                           "\"standard\""),
         "problem-spec validation should reject explicit propagator variants that disagree with "
         "the current legacy kind-backed linearity surface");
}

void FeynmanPrescriptionVocabularyTest() {
  Expect(amflow::ParseFeynmanPrescription(-1) == amflow::FeynmanPrescription::MinusI0,
         "raw -1 should map to the frozen -i0 prescription");
  Expect(amflow::ParseFeynmanPrescription(0) == amflow::FeynmanPrescription::None,
         "raw 0 should map to the frozen no-prescription token");
  Expect(amflow::ParseFeynmanPrescription(1) == amflow::FeynmanPrescription::PlusI0,
         "raw 1 should map to the frozen +i0 prescription");
  Expect(!amflow::ParseFeynmanPrescription(2).has_value(),
         "out-of-vocabulary raw prescription values should be rejected");
}

