  RecordingStaticBoundaryProvider baseline_provider("builtin::cutkosky-phase-space",
                                                    {MakeCutkoskyPhaseSpaceBoundaryCondition()});
  RecordingStaticBoundaryProvider inert_provider("builtin::cutkosky-phase-space",
                                                 {MakeCutkoskyPhaseSpaceBoundaryCondition()});
